using System.ComponentModel;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// --- Shared state for the note-taking tool ---
var notes = new List<ResearchNote>();

// --- Build the chat client through MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define the tools the agent can use ---
AITool[] tools =
[
    AIFunctionFactory.Create(SearchWebAsync, "search_web"),
    AIFunctionFactory.Create(ReadWebPageAsync, "read_web_page"),
    AIFunctionFactory.Create(SaveNote, "save_note"),
    AIFunctionFactory.Create(GetAllNotes, "get_all_notes"),
];

// --- Create the agent with Microsoft Agent Framework ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a thorough research agent. When given a topic you must:
        1. Search the web 2-3 times with varied queries to cover different angles.
        2. Read the most promising pages to gather detailed information.
        3. Save key findings as notes using the save_note tool.
        4. After gathering enough information, call get_all_notes to review your findings.
        5. Synthesize everything into a clear, well-structured summary with source URLs.

        Be systematic: search broadly, read selectively, note important facts,
        then summarize with citations.
        """,
    name: "Researcher",
    description: "Researches topics using web search and note-taking",
    tools: tools);

// --- Get the research topic ---
var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔬 Researching: {topic}\n");

// --- Run the agent ---
var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
    },
};

AgentResponse response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary:\n\n{topic}",
    session,
    runOptions);

// --- Display results ---
Console.WriteLine("\n════════════════════════════════════════");
Console.WriteLine("  📋 RESEARCH SUMMARY");
Console.WriteLine("════════════════════════════════════════\n");
Console.WriteLine(response.Text);

if (notes.Count > 0)
{
    Console.WriteLine("\n════════════════════════════════════════");
    Console.WriteLine("  📝 RESEARCH NOTES");
    Console.WriteLine("════════════════════════════════════════\n");

    for (var i = 0; i < notes.Count; i++)
    {
        Console.WriteLine($"  [{i + 1}] {notes[i].Title}");
