    [Description("Short title for the note")] string title,
    [Description("The note content with key facts and source URL")] string content)
{
    notes.Add(new ResearchNote(title, content));
    Console.WriteLine($"  💾 Note saved: \"{title}\"");
    return $"Note saved: \"{title}\" (total: {notes.Count})";
}

[Description("Retrieve all saved research notes to review before writing the final summary.")]
string GetAllNotes()
{
    if (notes.Count == 0)
        return "No notes saved yet.";

    var sb = new StringBuilder();
    for (var i = 0; i < notes.Count; i++)
    {
        sb.AppendLine($"[{i + 1}] {notes[i].Title}");
        sb.AppendLine($"    {notes[i].Content}");
        sb.AppendLine();
    }

    Console.WriteLine($"  📋 Retrieved {notes.Count} note(s)");
    return sb.ToString();
}

// ─── Helpers ────────────────────────────────────────────────────

static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    return Console.ReadLine()?.Trim() ?? "";
}

static string ParseSearchResults(string html)
{
    var sb = new StringBuilder();
    var resultRegex = new Regex(
        @"<a[^>]+class=""result__a""[^>]*href=""([^""]*?)""[^>]*>(.*?)</a>.*?" +
        @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
        RegexOptions.Singleline);

    var count = 0;
    foreach (Match match in resultRegex.Matches(html))
    {
        if (count >= 8)
            break;

        var url = match.Groups[1].Value.Trim();
        var title = StripHtml(match.Groups[2].Value).Trim();
        var snippet = StripHtml(match.Groups[3].Value).Trim();

        // DuckDuckGo wraps URLs in a redirect — extract the real destination
        var uddg = Regex.Match(url, @"uddg=([^&]+)");
        if (uddg.Success)
            url = Uri.UnescapeDataString(uddg.Groups[1].Value);

        if (!string.IsNullOrWhiteSpace(title))
        {
            sb.AppendLine($"[{++count}] {title}");
            sb.AppendLine($"    URL: {url}");
            sb.AppendLine($"    {snippet}");
            sb.AppendLine();
        }
    }

    return sb.Length > 0
        ? sb.ToString()
        : "No search results found. Try rephrasing the query.";
}

static string StripHtml(string html)
{
    // Remove script and style blocks
    html = Regex.Replace(html, @"<(script|style)[^>]*>.*?</\1>", "",
        RegexOptions.Singleline | RegexOptions.IgnoreCase);
    // Remove HTML tags
    html = Regex.Replace(html, @"<[^>]+>", " ");
    // Decode common entities
    html = html.Replace("&amp;", "&").Replace("&lt;", "<")
               .Replace("&gt;", ">").Replace("&quot;", "\"")
               .Replace("&#39;", "'").Replace("&nbsp;", " ");
    // Collapse whitespace
    html = Regex.Replace(html, @"\s+", " ").Trim();
    return html;
}

// ─── Types ──────────────────────────────────────────────────────

record ResearchNote(string Title, string Content);

